INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(10, 1, '2026-04-01 07:35:41', '2026-04-01 07:35:41', '<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"pro-portfolio\",\"tagName\":\"header\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"align\":\"full\",\"className\":\"has-no-underline\",\"style\":{\"spacing\":{\"blockGap\":\"0\",\"padding\":{\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group alignfull has-no-underline\" style=\"margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:0;padding-left:0\"><!-- wp:group {\"tagName\":\"section\",\"metadata\":{\"name\":\"Banner Section\"},\"align\":\"full\",\"className\":\"banner-section\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"30px\",\"left\":\"30px\",\"top\":\"var:preset|spacing|60\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<section class=\"wp-block-group alignfull banner-section\" id=\"Home\" style=\"padding-top:var(--wp--preset--spacing--60);padding-right:30px;padding-bottom:0;padding-left:30px\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"align\":\"wide\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"padding\":{\"right\":\"0\",\"left\":\"0\",\"top\":\"0\",\"bottom\":\"5rem\"},\"blockGap\":{\"top\":\"0\",\"left\":\"0\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|border\",\"width\":\"1px\"}}}} -->\n<div class=\"wp-block-columns alignwide are-vertically-aligned-center\" style=\"border-bottom-color:var(--wp--preset--color--border);border-bottom-width:1px;margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:5rem;padding-left:0\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":\"0px\",\"padding\":{\"top\":\"55px\",\"right\":\"0px\",\"bottom\":\"55px\",\"left\":\"0px\"}}},\"layout\":{\"inherit\":false,\"wideSize\":\"1500px\"}} -->\n<div class=\"wp-block-group alignwide\" style=\"padding-top:55px;padding-right:0px;padding-bottom:55px;padding-left:0px\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":3,\"style\":{\"typography\":{\"lineHeight\":\"1.5\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"5px\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\",\"fontSize\":\"normal\"} -->\n<h3 class=\"wp-block-heading has-text-align-left has-boulder-color has-text-color has-link-color has-normal-font-size\" style=\"letter-spacing:5px;line-height:1.5;text-transform:uppercase\">Welcome to my world</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"left\",\"style\":{\"typography\":{\"lineHeight\":\"1.2\",\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"spacing\":{\"margin\":{\"bottom\":\"var:preset|spacing|50\",\"top\":\"var:preset|spacing|50\"}}},\"textColor\":\"foreground\",\"fontSize\":\"extra-large\"} -->\n<h2 class=\"wp-block-heading has-text-align-left has-foreground-color has-text-color has-extra-large-font-size\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50);font-style:normal;font-weight:700;line-height:1.2\">Hi, I’m&nbsp;<mark style=\"background-color:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-pink-color\">N.Huynh</mark><br>a&nbsp;<strong>Designer.</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\"} -->\n<p class=\"has-text-align-left has-boulder-color has-text-color has-link-color\">\"Chào mừng bạn đến với thế giới sáng tạo của tôi. Nơi mỗi pixel đều có mục đích và mỗi điểm chạm đều mang lại giá trị. Tôi luôn khao khát học hỏi và áp dụng những công nghệ mới nhất để nâng tầm trải nghiệm số.\"</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"className\":\" animated animated-fadeInUp\",\"s