20px\",\"bottom\":\"0px\"},\"blockGap\":\"20px\"}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-buttons animated animated-fadeInUp\" style=\"margin-top:20px;margin-bottom:0px\"><!-- wp:button {\"textColor\":\"primary\",\"className\":\"is-style-fill\",\"style\":{\"color\":{\"gradient\":\"linear-gradient(145deg,rgb(226,232,236) 0%,rgb(255,255,255) 100%)\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"shadow\":\"var:preset|shadow|natural\",\"border\":{\"radius\":\"10px\",\"top\":{\"color\":\"var:preset|color|background-secondary\",\"width\":\"2px\"},\"right\":{\"color\":\"#ffffff00\",\"width\":\"2px\"},\"bottom\":{\"color\":\"#ffffff00\",\"width\":\"2px\"},\"left\":{\"color\":\"var:preset|color|background-secondary\",\"width\":\"2px\"}}}} -->\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link has-primary-color has-text-color has-background has-link-color wp-element-button\" href=\"#\" style=\"border-radius:10px;border-top-color:var(--wp--preset--color--background-secondary);border-top-width:2px;border-right-color:#ffffff00;border-right-width:2px;border-bottom-color:#ffffff00;border-bottom-width:2px;border-left-color:var(--wp--preset--color--background-secondary);border-left-width:2px;background:linear-gradient(145deg,rgb(226,232,236) 0%,rgb(255,255,255) 100%);box-shadow:var(--wp--preset--shadow--natural);font-style:normal;font-weight:700\">Get Started</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"textColor\":\"primary\",\"className\":\"is-style-outline\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"shadow\":\"var:preset|shadow|natural\",\"border\":{\"radius\":\"10px\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-primary-color has-text-color has