ulder\"}}}},\"textColor\":\"boulder\",\"fontSize\":\"tiny\"} /-->\n\n<!-- wp:post-terms {\"term\":\"category\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}},\"typography\":{\"textDecoration\":\"none\"}},\"textColor\":\"primary\",\"fontSize\":\"extra-small\"} /--></div>\n<!-- /wp:group -->\n\n<!-- wp:post-title {\"level\":3,\"isLink\":true,\"align\":\"wide\",\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"600\"}},\"textColor\":\"foreground\"} /--></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n<!-- /wp:post-template --></main>\n<!-- /wp:query --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"pro-portfolio\",\"tagName\":\"footer\"} /-->', 'Trang chủ', 'Hiển thị trang chủ của trang web của bạn, cho dù nó được đặt để hiển thị bài viết mới nhất hoặc một trang tĩnh. Mẫu Trang chủ ưu tiên hơn tất cả các mẫu.', 'inherit', 'closed', 'closed', '', '10-revision-v1', '', '', '2026-04-01 15:27:42', '2026-04-01 15:27:42', '', 10, 'http://localhost/huynh_profile/?p=50', 0, 'revision', '', 0);
